import { VexClient, Guardrail } from '@vex/sdk';

const client = new VexClient({ apiKey: 'your-vex-key' });

const auditGuardrail = Guardrail.fromLibrary('hipaa-audit-trail');

const azureAgentHandler = async (agentThread: any) => {
  const { input, tokensUsed, output } = agentThread;

  // Token limit check
  if (tokensUsed > 128000) {
    throw new Error('Thread token limit exceeded - truncate history');
  }

  // Audit all healthcare decisions
  const auditResult = await client.evaluate(output, {
    guardrails: [auditGuardrail],
    context: { patientId: 'deidentified', decisionType: 'clinical' }
  });

  return auditResult.cleanOutput;
};
